var e=[{id:`L2_1`,type:`dialog`,speaker:`LEAFNOD_VOICE_NULL_NULL`,text:{KOREA:`<color=#ffd34c>적 전자 시스템 프로토콜 분석 종료. X밴드 전술 통신파 간섭 가능.</color>`,JPN:`<color=#ffd34c>敵の電子システムプロトコル分析を終了。Xバンド戦術通信波への干渉可能。</color>`,ENG:`<color=#ffd34c>Analysis on the enemy C4I protocols is complete. Jamming of X-band tactical comms is now possible.</color>`,TWN:`<color=#ffd34c>敵方電子系統協議分析完畢，可以對X頻段戰術通信波進行干涉。</color>`},stage:{bg:`CORRIDOR`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`LEAFNOD_VOICE_NULL_NULL`,text:{KOREA:`<color=#ffd34c>제 2급 시스템 관리자 권한 탈취를 완료했습니다. 명령을.</color>`,JPN:`<color=#ffd34c>第2級のシステム管理者権限を奪取完了しました。命令をお願いします。</color>`,ENG:`<color=#ffd34c>Class 2 system administrator rights hijacked successfully. Awaiting your command.</color>`,TWN:`<color=#ffd34c>成功奪取二級系統管理者權限，請下達命令。</color>`},stage:{bg:`CORRIDOR`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`SYLVIA_DELTA_NULL_NULL`,text:{KOREA:`좋아!`,JPN:`やった！`,ENG:`Great!`,TWN:`很好！！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`SYLVIA_DELTA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`SYLVIA_DELTA_NULL_NULL`,text:{KOREA:`락다운 쇼크 버스터, 기동!`,JPN:`ロックダウンショックバスター、起動！`,ENG:`Activate lockdown shock buster!`,TWN:`封鎖衝擊炸裂，啟動！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`SYLVIA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`SOLDIER_REPLACER_NULL_NULL`,text:{KOREA:`통합 전술 시스템이 작동하지 않습니다!`,JPN:`統合戦術システムが作動しません！`,ENG:`Our integrated tactical system is down!`,TWN:`統合戰術系統無法動作！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`SOLDIER_REPLACER_NULL_NULL`,text:{KOREA:`서프레션 프로토콜 기동 실패!`,JPN:`サプレッションプロトコルの起動に失敗！`,ENG:`Suppression Protocol failed!`,TWN:`抑制協定啟動失敗！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`SOLDIER_REPLACER_NULL_NULL`,text:{KOREA:`기계화 부대 작동 정지! 시동이 걸리지 않습니다!`,JPN:`機械化部隊の作動停止！起動できません！`,ENG:`Mechanized units offline! We can’t get them started!`,TWN:`機械化部隊停止運作！無法啟動！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`COMMANDER_REPLACER_NULL_NULL`,text:{KOREA:`뭐? 이게 다 무슨 일이야?! 당장 원인 파악해!`,JPN:`なに？　いったいどういうことだ！？　直ちに原因を調べろ！`,ENG:`What? What’s going on?! Track down the cause right away!`,TWN:`什麼？所有部隊都發生這種事？！立即找出原因！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`COMMANDER_REPLACER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`SOLDIER_REPLACER_NULL_NULL`,text:{KOREA:`전자 시스템 전체가 강력한 외부 침투형 바이러스에 오염된 것 같습니다!`,JPN:`電子システム全体が強力な外部浸透型のウイルスに汚染されたようです！`,ENG:`The entire system seems to be compromised by a powerful virus!`,TWN:`所有電子系統似乎都遭受了外部滲透型病毒的感染！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`COMMANDER_REPLACER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`SOLDIER_REPLACER_NULL_NULL`,text:{KOREA:`전투 속행 불가!`,JPN:`戦闘続行不可！`,ENG:`We can’t proceed with the operation like this!`,TWN:`無法繼續戰鬥！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`COMMANDER_REPLACER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`COMMANDER_REPLACER_NULL_NULL`,text:{KOREA:`......이런 젠장! 전 부대! 일시 후퇴한다!`,JPN:`……くそっ！　全部隊はいったん後退せよ！`,ENG:`Damn it... All units! Fall back!`,TWN:`……該死！全體部隊！暫時性撤退！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`COMMANDER_REPLACER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`XIAOLIN_ALT_NULL_NULL`,text:{KOREA:`사격 중지! 놈들이 물러난다.`,JPN:`射撃中止！　奴らが下がっている。`,ENG:`Cease fire! They’re falling back.`,TWN:`停止射擊！那些傢伙撤退了。`},stage:{bg:`CORRIDOR`,slots:{L:{char_id:`XIAOLIN_ALT_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`KIMSOBIN_ALT_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L23_1`,type:`dialog`,speaker:`KIMSOBIN_ALT_NULL_NULL`,text:{KOREA:`끄, 끝난 거야?`,JPN:`お、終わったんですか？`,ENG:`I-is it over?`,TWN:`結、結束了嗎？`},stage:{bg:`CORRIDOR`,slots:{L:{char_id:`XIAOLIN_ALT_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`KIMSOBIN_ALT_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L25_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`일단은.`,JPN:`とりあえずはね。`,ENG:`For now.`,TWN:`暫時是這樣沒錯。`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`하지만 다시 몰려올 거야. 저건 전초부대일 뿐이니까.`,JPN:`でも、またやってくると思う。あれは前哨部隊に過ぎないから。`,ENG:`But they’ll be back. They were only the vanguard.`,TWN:`但他們還會再殺過來的，那些只是前哨部隊而已。`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};